mapper.select:
/* com.shop.mapper.frontWeb.Product.selectProductInfoListPaging */ SELECT P.ID AS id , P.PARTNER_ID AS partnerId , P.PROD_CD AS prodCd , P.PROD_NM AS prodNm , P.PROD_TP AS prodTp , P.PROD_DET_TP AS prodDetTp , P.COMPOSITION AS composition , P.REP_FILE_ID AS repFileId , P.DETAIL_FILE_ID AS detailFileId , P.SIZE_FILE_ID AS sizeFileId , P.ETC_FILE_ID AS etcFileId , P.MAKE_YMD AS makeYmd , P.ORG_AMT AS orgAmt , P.SELL_AMT AS sellAmt , P.DISCOUNT_RATE AS discountRate , P.IS_SPRING AS isSpring , P.IS_SUMMER AS isSummer , P.IS_AUTUMN AS isAutumn , P.IS_WINTER AS isWinter , P.FAVORITE_POINT AS favoritePoint , FD.SYS_FILE_NM AS sysFileNm FROM TB_PRODUCT P LEFT JOIN TB_FILE_DET FD ON FD.FILE_ID = P.REP_FILE_ID AND FD.DEL_YN = 'N' AND FD.FILE_SEQ = 1
AND P.DEL_YN = 'N'
AND P.ID > #{filter.lastId}
AND EXISTS ( SELECT CP.ID FROM TB_CATEGORY_PRODUCT CP JOIN TB_PARTNER_CODE PC ON PC.PARTNER_ID = #{filter.partnerId} AND PC.CODE_UPPER = 'P0001' AND PC.DEL_YN = 'N' AND PC.ID = CP.CATEGORY_ID WHERE CP.PRODUCT_ID = P.ID
AND PC.CODE_CD = #{filter.categoryId}
)
AND P.PARTNER_ID = #{filter.partnerId}
ORDER BY P.SELL_AMT ASC, P.ID ASC ORDER BY P.SELL_AMT DESC, P.ID ASC ORDER BY P.FAVORITE_POINT DESC, P.ID ASC ORDER BY P.ID DESC
LIMIT #{pageRowCount} + 1;

/* com.shop.mapper.frontWeb.Product.selectProductSearchList */ SELECT DISTINCT P.ID AS id , P.PARTNER_ID AS partnerId , P.PROD_CD AS prodCd , P.PROD_NM AS prodNm , P.PROD_TP AS prodTp , P.PROD_DET_TP AS prodDetTp , P.COMPOSITION AS composition , P.REP_FILE_ID AS repFileId , P.DETAIL_FILE_ID AS detailFileId , P.SIZE_FILE_ID AS sizeFileId , P.ETC_FILE_ID AS etcFileId , P.MAKE_YMD AS makeYmd , P.ORG_AMT AS orgAmt , P.SELL_AMT AS sellAmt , P.DISCOUNT_RATE AS discountRate , P.IS_SPRING AS isSpring , P.IS_SUMMER AS isSummer , P.IS_AUTUMN AS isAutumn , P.IS_WINTER AS isWinter , P.FAVORITE_POINT AS favoritePoint , FD.SYS_FILE_NM AS sysFileNm FROM TB_PRODUCT P LEFT JOIN TB_FILE_DET FD ON FD.FILE_ID = P.REP_FILE_ID AND FD.DEL_YN = 'N' AND FD.FILE_SEQ = 1 LEFT JOIN TB_PRODUCT_DET PD ON PD.PRODUCT_ID = P.ID AND PD.SLEEP_YN = 'N'
AND P.DEL_YN = 'N' AND P.PARTNER_ID = #{filter.partnerId}
AND P.ID > #{filter.lastId}
AND ( P.PROD_NM LIKE CONCAT('%', #{filter.keyword}, '%') OR PD.PRODUCT_DET_COLOR LIKE CONCAT('%', #{filter.keyword}, '%') )
ORDER BY P.ID LIMIT #{pageRowCount} + 1;
